-- Restore missing April 2026 monthly_reports from old PDF backup.
-- Source PDF: C:\Users\ASUS\Downloads\Rekap_Laporan_April_2026.pdf
-- Extracted rows: 594
-- Safety: this inserts only missing rows. Existing April 2026 rows are NOT overwritten.

BEGIN;

CREATE TEMP TABLE _restore_april_2026_reports (
  kelas integer NOT NULL,
  rombel text NOT NULL,
  nama text NOT NULL,
  program_type text NOT NULL,
  iqra_level text,
  end_iqra_level text,
  start_page integer NOT NULL,
  end_page integer NOT NULL,
  pages_read integer NOT NULL,
  target_pages integer NOT NULL,
  achievement_status text NOT NULL,
  notes text
) ON COMMIT DROP;


SELECT 'rows_from_pdf' AS check_name, count(*) AS total FROM _restore_april_2026_reports;

SELECT 'matched_students' AS check_name, count(*) AS total
FROM _restore_april_2026_reports r
JOIN public.students s
  ON s.kelas = r.kelas
 AND s.rombel = r.rombel
 AND lower(regexp_replace(trim(s.nama), '\s+', ' ', 'g')) = lower(regexp_replace(trim(r.nama), '\s+', ' ', 'g'));

SELECT 'existing_april_reports_before_restore' AS check_name, count(*) AS total
FROM public.monthly_reports
WHERE month = 4 AND year = 2026;

SELECT r.kelas, r.rombel, r.nama
FROM _restore_april_2026_reports r
LEFT JOIN public.students s
  ON s.kelas = r.kelas
 AND s.rombel = r.rombel
 AND lower(regexp_replace(trim(s.nama), '\s+', ' ', 'g')) = lower(regexp_replace(trim(r.nama), '\s+', ' ', 'g'))
WHERE s.id IS NULL
ORDER BY r.kelas, r.rombel, r.nama;

WITH inserted AS (
    student_id, month, year, program_type, iqra_level, end_iqra_level,
    start_page, end_page, pages_read, target_pages, achievement_status, notes, created_by
  )
  SELECT
    s.id, 4, 2026, r.program_type, r.iqra_level, r.end_iqra_level,
    r.start_page, r.end_page, r.pages_read, r.target_pages, r.achievement_status, r.notes, NULL
  FROM _restore_april_2026_reports r
  JOIN public.students s
    ON s.kelas = r.kelas
   AND s.rombel = r.rombel
   AND lower(regexp_replace(trim(s.nama), '\s+', ' ', 'g')) = lower(regexp_replace(trim(r.nama), '\s+', ' ', 'g'))
  ON CONFLICT (student_id, month, year) DO NOTHING
  RETURNING student_id
)
SELECT 'inserted_missing_april_reports' AS check_name, count(*) AS total FROM inserted;

SELECT 'existing_april_reports_after_restore' AS check_name, count(*) AS total
FROM public.monthly_reports
WHERE month = 4 AND year = 2026;

COMMIT;
